import java.util.Arrays;
import java.util.ArrayList;

class DistanceLimitedPathsExist {
    public DistanceLimitedPathsExist(int n, int[][] edgeList) {
        id = new int[n];
        for (int i = 0; i < n; ++i) {
            id[i] = i;
        }
        Arrays.sort(edgeList, (a, b) -> Integer.compare(a[2], b[2]));
        for (int[] edge : edgeList) {
            int p = find(edge[0]);
            int q = find(edge[1]);
            if (p != q) {
                id[p] = id[q];
                mst.add(edge);
            }
        }
    }

    public boolean query(int p, int q, int limit) {
        for (int[] edge : mst) {
            if (edge[2] >= limit) break;
            p = union_set(edge[0], p);
            q = union_set(edge[1], q);
            if (p == q) return true;
        }
        return false;
    }

    private int find(int x) {
        if (id[x] != x) {
            id[x] = find(id[x]);
        }
        return id[x];
    }

    private int union_set(int x, int y) {
        int px = find(x);
        int py = find(y);
        if (px != py) {
            id[px] = py;
        }
        return py;
    }

    private int[] id;
    private ArrayList<int[]> mst = new ArrayList<>();
}
